// export default AddProduct;import React, { useState, useEffect, useContext } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { AuthContext } from "../../context/AuthContext";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const AddProduct = () => {
  const navigate = useNavigate();
  const { user, logout } = useContext(AuthContext);
  const [categories, setCategories] = useState([]);

  const [formData, setFormData] = useState({
    name: "",
    description: "",
    categoryId: "",
    price: "",
    discountPrice: "",
    stock: 0,
    flowerType: "",
    season: "Quanh năm",
    isFeatured: false,
    tags: [],
  });

  const [tagsInput, setTagsInput] = useState("");
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Lấy danh mục
  useEffect(() => {
    const fetchCats = async () => {
      try {
        const res = await axios.get(`${API_URL}/api/categories`);
        setCategories(res.data.categories || []);
      } catch (err) {
        console.error(err);
      }
    };
    fetchCats();
  }, []);

  // Preview ảnh
  useEffect(() => {
    if (!files.length) return setPreviews([]);
    const newPreviews = files.map((file) => URL.createObjectURL(file));
    setPreviews(newPreviews);
    return () => newPreviews.forEach((url) => URL.revokeObjectURL(url));
  }, [files]);

  // Tag input
  useEffect(() => {
    setFormData((prev) => ({ ...prev, tags: tagsInput.split(",").map(t => t.trim()).filter(Boolean) }));
  }, [tagsInput]);

  const handleChange = (e) =>
    setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleFilesChange = (e) => {
    const selected = Array.from(e.target.files);
    if (selected.length + files.length > 5) {
      alert("Tối đa 5 ảnh thôi nhé 🌸");
      return;
    }
    setFiles([...files, ...selected]);
  };

  const removePreview = (i) => {
    setFiles(files.filter((_, idx) => idx !== i));
    setPreviews(previews.filter((_, idx) => idx !== i));
  };

  const getToken = () =>
    user?.token || JSON.parse(localStorage.getItem("userInfo"))?.token;

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!formData.name || !formData.categoryId || !formData.price) {
      setError("Vui lòng nhập đủ thông tin bắt buộc!");
      return;
    }

    const token = getToken();
    if (!token) {
      alert("Phiên đăng nhập hết hạn, vui lòng đăng nhập lại!");
      logout?.();
      return;
    }

    try {
      setLoading(true);
      let imageUrls = [];

      // 🖼️ Upload ảnh
      if (files.length > 0) {
        const imgForm = new FormData();
        files.forEach((f) => imgForm.append("images", f));

        const uploadRes = await axios.post(`${API_URL}/api/upload`, imgForm, {
          headers: {
            "Content-Type": "multipart/form-data",
            Authorization: `Bearer ${token}`,
          },
        });
        imageUrls = uploadRes.data.urls || [];
      }

      // 🌷 Gửi sản phẩm
      const productData = { ...formData, price: +formData.price, discountPrice: +formData.discountPrice || 0, images: imageUrls };
      await axios.post(`${API_URL}/api/products`, productData, {
        headers: { Authorization: `Bearer ${token}` },
      });

      alert("✅ Thêm sản phẩm thành công!");
      navigate("/admin/products");
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Lỗi khi thêm sản phẩm");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 to-blue-50 py-10 px-4">
      <div className="max-w-4xl mx-auto bg-white shadow-lg rounded-xl p-8">
        <h2 className="text-3xl font-semibold text-gray-800 mb-6 text-center">
          🌸 Thêm Sản Phẩm Mới
        </h2>

        {error && (
          <div className="bg-red-100 text-red-600 p-3 rounded mb-4">{error}</div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Thông tin cơ bản */}
          <div className="grid grid-cols-2 gap-6">
            <input name="name" value={formData.name} onChange={handleChange} placeholder="Tên sản phẩm" className="border rounded px-3 py-2" />
            <select name="categoryId" value={formData.categoryId} onChange={handleChange} className="border rounded px-3 py-2">
              <option value="">-- Chọn danh mục --</option>
              {categories.map((c) => (
                <option key={c._id} value={c._id}>{c.name}</option>
              ))}
            </select>
            <input name="price" type="number" value={formData.price} onChange={handleChange} placeholder="Giá gốc" className="border rounded px-3 py-2" />
            <input name="discountPrice" type="number" value={formData.discountPrice} onChange={handleChange} placeholder="Giá khuyến mãi" className="border rounded px-3 py-2" />
          </div>

          {/* Ảnh */}
          <div>
            <label className="block mb-1 font-medium">Ảnh (tối đa 5 ảnh)</label>
            <input type="file" multiple accept="image/*" onChange={handleFilesChange} />
            <div className="grid grid-cols-5 gap-3 mt-3">
              {previews.map((src, i) => (
                <div key={i} className="relative">
                  <img src={src} alt="" className="w-24 h-24 object-cover rounded" />
                  <button type="button" onClick={() => removePreview(i)} className="absolute top-1 right-1 bg-red-500 text-white rounded-full px-2 py-0.5">x</button>
                </div>
              ))}
            </div>
          </div>

          {/* Nút */}
          <div className="flex justify-end">
            <button type="submit" disabled={loading} className="bg-pink-500 text-white px-6 py-2 rounded hover:bg-pink-600">
              {loading ? "Đang lưu..." : "Thêm sản phẩm"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddProduct;
